/* com.erns.coching.search.mapper.CochingEsTvDAO.getList */

SELECT 
	ZZ.*
FROM 
	(	
		SELECT

		FROM T_ES_TV AA					






				ORDER BY AA.TV_SEQ


	) ZZ

	OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.search.mapper.CochingEsTvDAO.getListVo */

SELECT 
	ZZ.*
FROM 
	(	
		SELECT

		FROM T_ES_TV AA					






				ORDER BY AA.TV_SEQ


	) ZZ

	OFFSET #{offset} LIMIT #{rowSize}

    	/* com.erns.coching.search.mapper.CochingEsTvDAO.load */

		SELECT

		FROM T_ES_TV AA

			AND AA.TV_SEQ = #{value, jdbcType=INTEGER}

mapper.update:
		/* com.erns.coching.search.mapper.CochingEsTvDAO.dropTable */

    DROP TABLE IF EXISTS T_ES_TV;

		commit;

/* com.erns.coching.search.mapper.CochingEsTvDAO.createTable */
CREATE TABLE IF NOT EXISTS T_ES_TV AS
AND COALESCE(CTV.USE_YN, 'Y') = 'Y' AND COALESCE(CTV.DEL_YN, 'N') = 'N'

mapper.select:
/* com.erns.coching.search.mapper.CochingEsTvDAO.getListVoForEsRenewDeleteItems */
SELECT 'delete' AS job , CTV.tv_seq , CTV.DEL_YN , CTV.USE_YN FROM T_CH_TV CTV /* TV 마스터 */
#{item, jdbcType=INTEGER}
GROUP BY CTV.tv_seq , CTV.DEL_YN , CTV.USE_YN HAVING NOT ( COALESCE(CTV.USE_YN, 'Y') = 'Y' AND COALESCE(CTV.DEL_YN, 'N') = 'N' ) /* ORDER BY CTV.tv_seq */
